SELECT AVG(nns.novelty_score) as avg_node_novelty
FROM node_novelty_scores nns
WHERE nns.network_id = 1 AND nns.turn = 1;

SELECT network_id, pct_nodes_explored
FROM exploration_history
WHERE turn = 0;

SELECT AVG(pct_nodes_explored) AS average_nodes_explored
FROM exploration_history
WHERE network_id = 0;

SELECT AVG(e.pct_nodes_explored) AS average_pct_nodes_explored
FROM exploration_history e
WHERE e.network_id = 1;

SELECT
    (SELECT AVG(novelty_score) FROM node_novelty_scores WHERE network_id = 1 AND turn = 5) AS average_node_novelty,
    (SELECT AVG(novelty_score) FROM link_novelty_scores WHERE network_id = 1 AND turn = 5) AS average_link_novelty;
